INSERT INTO CLIENT_RELATED (ID_RELATED, TITLE)
VALUES (1, 'Related fixture');

INSERT INTO CLIENT_RELATED (ID_RELATED, TITLE)
WITH RECURSIVE seq AS (
    SELECT 2 AS n
    UNION ALL
    SELECT n + 1 FROM seq WHERE n < 40
)
SELECT n, CONCAT('Related ', LPAD(n, 2, '0'))
FROM seq;

UPDATE CLIENT_RELATED SET TITLE = 'Related Gold' WHERE ID_RELATED = 2;
UPDATE CLIENT_RELATED SET TITLE = 'Related Silver' WHERE ID_RELATED = 3;
UPDATE CLIENT_RELATED SET TITLE = 'Related Bronze' WHERE ID_RELATED = 4;
